<!-- 修改要展示的markdown文件时，要修改两个路径以及一个正则表达式！！！ -->
<template>
  <el-container class="Page-container">

    <el-header class="Header-container">
      <div class="header-content">Lysssyo's Personal Page</div>
    </el-header>

    <el-container class="Main-container">
      <el-aside class="Aside-container" style="width: 15%;">
        <el-col>
          <el-menu default-active="2" class="el-menu-vertical-demo">
            <el-submenu index="1">
              <template slot="title">
                <i class="el-icon-reading"></i>
                <span>Learning Notes</span>
              </template>
              <el-menu-item-group>
                <el-menu-item index="1-1">
                  <router-link to="/Algorithm">
                    页面1
                  </router-link>
                </el-menu-item>
                <el-menu-item index="1-2">
                  <router-link to="/test">页面2</router-link>
                </el-menu-item>
                <el-menu-item index="1-3">
                  <router-link to="/mobileAlgorithm">页面3</router-link>
                </el-menu-item>
              </el-menu-item-group>
            </el-submenu>
          </el-menu>
        </el-col>
      </el-aside>

      <el-main class="Content-container" style="width: 85%;">
        <div class="blogPage">
          <!-- 使用 mavon-editor 组件展示 Markdown 内容 -->
          <mavon-editor style="position:static" :value="markdownContent" :editable="false" :subfield="true"
            :defaultOpen="'preview'" :toolbarsFlag="false" :scrollStyle="true" :ishljs="true" />
        </div>
      </el-main>

    </el-container>
  </el-container>
</template>

<script>
import axios from 'axios';
import 'mavon-editor/dist/css/index.css';
import { mavonEditor } from 'mavon-editor';

export default {
  components: {
    mavonEditor
  },
  data() {
    return {
      markdownContent: ''
    };
  },
  created() {
    this.fetchMarkdownContent();
  },
  methods: {
    fetchMarkdownContent() {
  const githubUrl = 'https://raw.githubusercontent.com/Lysssyo/MyAlgorithm/main/DataStructuresAlgorithm.md';
  axios.get(githubUrl)
    .then(response => {
      let markdownContent = response.data;
      // 替换图片标签为展示图片的 HTML 标签
      markdownContent = markdownContent.replace(
        /<\s*img\s+src="([^"]*)"\s+alt="([^"]*)"\s+style="([^"]*)"\s*\/>|!\[.*?\]\((.*?)\)/g,
        (match, imgSrc, imgAlt, imgStyle, markdownImageUrl) => {
          // 提取正确的图片链接
          const imageUrl = imgSrc || markdownImageUrl;
          // 构建 GitHub 仓库中图片的 URL
          const githubImageUrl = `https://raw.githubusercontent.com/Lysssyo/MyAlgorithm/main/${imageUrl}`;
          // 返回展示图片的 HTML 标签
          return `<img src="${githubImageUrl}" alt="${imgAlt}" style="${imgStyle}" />`;
        }
      );
      this.markdownContent = markdownContent;
      
    })
    .catch(error => {
      console.error('Error fetching markdown content:', error);
    });
  }}

};
</script>


<style>
/* 最大的容器，包括头部、左菜单以及main */
.Page-container {
  width: 100%;
  height: 97vh;
  /* 使用视口高度作为容器的高度 */
  box-sizing: border-box;
  /* 使容器的大小包括内边距和边框 */
  padding: 0px;
  /* 内边距 */
  margin: 0;
  /* 清除默认的外边距 */
  border-radius: 20px;
  /* 添加 border-radius 属性使容器边角圆润 */
  overflow: hidden;
  /* 隐藏容器内容溢出的部分，以免边角的圆润效果被遮挡 */
}

/* 头部 */
.Header-container {
  height: 10%;
  background-color: darkgray;
}

/* 头部中的唯一的div */
.header-content {
  font-family: 'Microsoft YaHei', sans-serif;
  font-size: 35px;
  color: rgb(12, 13, 13);
}

/* 菜单以及右边的<el-main> */
.Main-container {
  height: 90%;
  /* 占Page-container的90% */
}

/* 菜单组件 */
.Aside-container {
  border-right: 1px solid #ddd;
  /* 添加右边线 */
  /* 菜单的宽度在标签中设置（只能在标签设置，在这里设置没反应） */
}

.Content-container {
  width: 85%;
  height: 100%;

}

/* main中唯一的div */
.Inner-container {
  width: 100%;
  /* 默认宽度 */
  height: 100%;
  /* 默认高度 */
}

/* 未访问状态下的链接样式 */
a:link {
    display: block;
    /* 设置链接为块级显示 */
    color: rgb(0, 0, 0);
    /* 设置链接颜色为黑色 */
    text-decoration: none;
    /* 移除下划线 */
}

/* 访问后状态下的链接样式 */
a:visited {
    color: rgb(0, 0, 0);
    /* 设置链接颜色为黑色，与未访问状态相同 */
    text-decoration: none;
    /* 移除下划线，与未访问状态相同 */
}

/* 鼠标悬停状态下的链接样式 */
a:hover {
    color: rgb(0, 0, 0);
    /* 设置链接颜色为黑色，与未访问状态相同 */
    text-decoration: none;
    /* 移除下划线，与未访问状态相同 */
}
</style>
